-- ----------------------------
-- Table structure for rucp_task_process
-- ----------------------------
DROP TABLE IF EXISTS `rucp_task_process`;
CREATE TABLE `rucp_task_process`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '表id',
  `task_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '任务编码',
  `position` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '步骤位置， input, standard, filters, output,setting',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '算子数据',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 189 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '算子过程' ROW_FORMAT = Compact;

